import{_ as o}from"./chunks/audio-sections.BTOGBP1S.js";import{_ as t,o as i,c as r,ag as a}from"./chunks/framework._658-eYr.js";const m=JSON.parse('{"title":"Audio Production","description":"","frontmatter":{},"headers":[],"relativePath":"guide/audio.md","filePath":"guide/audio.md"}'),s={name:"guide/audio.md"};function n(l,e,c,d,u,p){return i(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="audio-production" tabindex="-1">Audio Production <a class="header-anchor" href="#audio-production" aria-label="Permalink to &quot;Audio Production&quot;">​</a></h1><p>The Audio panel generates speech from your scripts using text-to-speech, handles uploaded voiceovers with timestamp-based splitting, supports sound effect sections, and can layer background music under the voice track.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>A script in <strong>Review</strong> or <strong>Final</strong> status (drafts are blocked)</li><li>A voice configured in <a href="/CRAFT/guide/settings.html">Settings</a> or selected per-project</li></ul><h2 id="two-modes" tabindex="-1">Two Modes <a class="header-anchor" href="#two-modes" aria-label="Permalink to &quot;Two Modes&quot;">​</a></h2><h3 id="tts-mode-ai-voice" tabindex="-1">TTS Mode (AI Voice) <a class="header-anchor" href="#tts-mode-ai-voice" aria-label="Permalink to &quot;TTS Mode (AI Voice)&quot;">​</a></h3><p>Generate speech from script text using one of five TTS providers:</p><table tabindex="0"><thead><tr><th>Provider</th><th>Voices</th><th>Cost</th><th>Quality</th></tr></thead><tbody><tr><td><strong>Edge TTS</strong></td><td>300+ Microsoft Neural voices</td><td>Free</td><td>Good</td></tr><tr><td><strong>ElevenLabs</strong></td><td>Premium cloned/generated voices</td><td>Paid</td><td>Excellent</td></tr><tr><td><strong>OpenAI</strong></td><td>6 voices</td><td>Paid</td><td>Very Good</td></tr><tr><td><strong>OpenedAI Speech</strong></td><td>6 voices (local GPU)</td><td>Free</td><td>Very Good</td></tr><tr><td><strong>RVC Voice Clone</strong></td><td>Your trained voice models</td><td>Free (GPU)</td><td>Excellent</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Edge TTS is the default — no API key needed. <strong>OpenedAI Speech</strong> and <strong>RVC Voice Clone</strong> are also free if you have a GPU — start with <code>docker compose --profile gpu up -d</code>.</p></div><h3 id="upload-mode-recorded-voiceover" tabindex="-1">Upload Mode (Recorded Voiceover) <a class="header-anchor" href="#upload-mode-recorded-voiceover" aria-label="Permalink to &quot;Upload Mode (Recorded Voiceover)&quot;">​</a></h3><p>Upload your own recorded voiceover and split it into sections by timestamp:</p><ol><li>Create a project in <strong>Upload</strong> mode</li><li>Upload your voiceover recording (MP3, WAV, OGG, FLAC)</li><li>Set start/end timestamps (mm:ss) for each section</li><li>Click <strong>Split All</strong> — sections are extracted as lossless WAV files</li><li>Re-upload individual sections if needed (re-record a single section without re-doing everything)</li></ol><div class="info custom-block"><p class="custom-block-title">Lossless Splits</p><p>Upload splits use WAV format to preserve audio quality. You can replace any section independently without generation loss.</p></div><h2 id="creating-a-project" tabindex="-1">Creating a Project <a class="header-anchor" href="#creating-a-project" aria-label="Permalink to &quot;Creating a Project&quot;">​</a></h2><ol><li>Navigate to <strong>Audio &gt; Create</strong></li><li>Select a script (must be Review or Final status)</li><li>Choose <strong>AI Voice (TTS)</strong> or <strong>Upload</strong> mode</li><li>If TTS: select a voice and service</li><li>Click <strong>Create Project</strong></li></ol><p>The script is automatically parsed into sections.</p><h2 id="section-parsing" tabindex="-1">Section Parsing <a class="header-anchor" href="#section-parsing" aria-label="Permalink to &quot;Section Parsing&quot;">​</a></h2><p>The parser uses three strategies (in order):</p><ol><li><strong>Screenplay format</strong> — detects stage directions <code>*(...)* </code> and character dialog <code>**Name:** text</code></li><li><strong>Structural markers</strong> — splits on <code>### headings</code>, <code>---</code> dividers, and <code>**Bold Headers**</code></li><li><strong>Paragraph fallback</strong> — splits on double newlines if the above produce only 1 section</li></ol><div class="info custom-block"><p class="custom-block-title">Stage Directions</p><p>Text in <code>*(stage direction)*</code> markers becomes <strong>scene context</strong> — it&#39;s not spoken by TTS but appears as production notes you can show/hide per section.</p></div><h2 id="sound-effect-sections" tabindex="-1">Sound Effect Sections <a class="header-anchor" href="#sound-effect-sections" aria-label="Permalink to &quot;Sound Effect Sections&quot;">​</a></h2><p>Insert SFX/transition sections anywhere in the timeline:</p><ol><li>Click the <strong>+</strong> button between sections</li><li>Choose <strong>Sound Effect</strong> (instead of Speech)</li><li>Upload an audio file for the SFX (WAV, MP3, etc.)</li><li>SFX sections appear with an amber badge and Music icon</li></ol><p>Use SFX sections for: transition stingers, sound effects, intro/outro jingles, ambient breaks.</p><h2 id="background-music" tabindex="-1">Background Music <a class="header-anchor" href="#background-music" aria-label="Permalink to &quot;Background Music&quot;">​</a></h2><p>Layer background music under the voice track:</p><ol><li>Expand <strong>Background Track</strong> below the section timeline</li><li>Choose <strong>Upload</strong> or <strong>Generate</strong> (if MusicGen GPU service is running): <ul><li><strong>Upload</strong> — any audio file (MP3, WAV, OGG, FLAC)</li><li><strong>Generate</strong> — describe the music (e.g. &quot;upbeat lo-fi hip hop&quot;), set duration (5-30s), click Generate</li></ul></li><li>Configure: <ul><li><strong>Volume</strong> — 0-100% (default 15%)</li><li><strong>Fade In/Out</strong> — seconds for gradual volume ramp</li><li><strong>Mode</strong> — Loop (repeats to match voice), Trim (cuts at voice end), Once (plays once)</li></ul></li><li>Background is mixed in during <strong>Merge</strong></li></ol><div class="tip custom-block"><p class="custom-block-title">MusicGen</p><p>The Generate tab appears when the MusicGen GPU service is running (<code>docker compose --profile gpu up -d</code>). It creates instrumental tracks from text prompts using Meta&#39;s AudioCraft model.</p></div><h3 id="standalone-music-generation" tabindex="-1">Standalone Music Generation <a class="header-anchor" href="#standalone-music-generation" aria-label="Permalink to &quot;Standalone Music Generation&quot;">​</a></h3><p>The <strong>Audio &gt; Music</strong> panel generates tracks without needing an audio project:</p><ol><li>Describe the music (e.g. &quot;upbeat lo-fi hip hop, chill vibes&quot;)</li><li>Set duration (5-30s) and click <strong>Generate Music</strong></li><li>Play back generated tracks inline with the play button</li><li><strong>Download</strong> as WAV or <strong>Save to Project</strong> as background music via the dropdown</li><li>Use <strong>AI Generate</strong> to auto-create a prompt based on your channel&#39;s topics</li></ol><p>Generated tracks persist for the session — you can preview multiple takes and pick the best one.</p><h2 id="generating-audio" tabindex="-1">Generating Audio <a class="header-anchor" href="#generating-audio" aria-label="Permalink to &quot;Generating Audio&quot;">​</a></h2><ul><li><strong>Generate All</strong> — processes every pending section sequentially</li><li><strong>Generate One</strong> — click refresh on any section to generate just that one</li><li><strong>Regenerate</strong> — re-generate with different voice settings</li></ul><p>Each section shows its status: pending, generating, ready, or error.</p><h2 id="voice-controls" tabindex="-1">Voice Controls <a class="header-anchor" href="#voice-controls" aria-label="Permalink to &quot;Voice Controls&quot;">​</a></h2><ul><li><strong>Speed</strong> — playback speed multiplier (Edge TTS, OpenAI)</li><li><strong>Stability</strong> (ElevenLabs) — lower = more expressive, higher = more consistent</li><li><strong>Similarity Boost</strong> (ElevenLabs) — how closely to match the original voice</li></ul><h2 id="linking-resources" tabindex="-1">Linking Resources <a class="header-anchor" href="#linking-resources" aria-label="Permalink to &quot;Linking Resources&quot;">​</a></h2><p>Click the <strong>paperclip</strong> icon on any section to link downloaded resources (images, video, audio) from your Resource Library. Linked resources appear as chips — useful for tracking which B-roll goes with which section for later video assembly.</p><h2 id="text-preprocessing" tabindex="-1">Text Preprocessing <a class="header-anchor" href="#text-preprocessing" aria-label="Permalink to &quot;Text Preprocessing&quot;">​</a></h2><p>Edge TTS doesn&#39;t support SSML, so text is automatically preprocessed:</p><ul><li>Dashes become commas (natural pauses)</li><li>Ellipses become periods (longer pauses)</li><li>Units spelled out: <code>°C</code> becomes &quot;degrees C&quot;</li><li>Abbreviations expanded: <code>e.g.</code> becomes &quot;for example&quot;</li></ul><h2 id="merging" tabindex="-1">Merging <a class="header-anchor" href="#merging" aria-label="Permalink to &quot;Merging&quot;">​</a></h2><p>Click <strong>Merge</strong> to combine all ready sections into a single audio file:</p><ul><li>Configurable silence gaps between sections (0-10000ms)</li><li>Mixed formats supported (WAV + MP3 sections normalized automatically)</li><li>If a background track is configured, it&#39;s layered under the voice with fade in/out</li></ul><p>The final output is an MP3 file ready for video production.</p><h2 id="voice-cloning-rvc" tabindex="-1">Voice Cloning (RVC) <a class="header-anchor" href="#voice-cloning-rvc" aria-label="Permalink to &quot;Voice Cloning (RVC)&quot;">​</a></h2><p>Clone your voice using RVC v2 — it post-processes any TTS output into your custom voice. Requires the GPU profile.</p><h3 id="step-1-collect-voice-samples" tabindex="-1">Step 1: Collect Voice Samples <a class="header-anchor" href="#step-1-collect-voice-samples" aria-label="Permalink to &quot;Step 1: Collect Voice Samples&quot;">​</a></h3><p>Record or gather 10-50 minutes of clean audio of the target voice.</p><ul><li>Avoid background music or noise — consistent mic setup and room acoustics improve results</li><li>Multiple recordings from the same session work best</li><li>Supported formats: WAV, MP3, OGG, FLAC, M4A</li></ul><p>Navigate to <strong>Audio &gt; Train Voice</strong> and drag-and-drop your files into the upload zone. The progress bar tracks total duration — aim for at least 10 minutes (30 minutes ideal).</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can also record audio externally and upload it via <a href="./audio.html#upload-mode">Audio &gt; Create</a> in Upload mode, then export the sections as WAV files for training input.</p></div><h3 id="step-2-train-a-model" tabindex="-1">Step 2: Train a Model <a class="header-anchor" href="#step-2-train-a-model" aria-label="Permalink to &quot;Step 2: Train a Model&quot;">​</a></h3><p>Training happens outside CRAFT using free tools:</p><ul><li><strong><a href="https://github.com/IAHispano/Applio" target="_blank" rel="noreferrer">Applio</a></strong> — recommended GUI for RVC training (free, runs locally)</li><li><strong>Google Colab notebooks</strong> — free GPU training in the cloud</li></ul><p>Use your uploaded voice samples as input. Training takes 20-60 minutes depending on settings (2000-6000 steps). The output is a <code>.pth</code> model file.</p><h3 id="step-3-upload-your-model" tabindex="-1">Step 3: Upload Your Model <a class="header-anchor" href="#step-3-upload-your-model" aria-label="Permalink to &quot;Step 3: Upload Your Model&quot;">​</a></h3><ol><li>In the <strong>Upload Voice Model</strong> section, select your <code>.pth</code> file (or a <code>.zip</code> containing <code>.pth</code> + <code>.index</code>)</li><li>The model appears in the Trained Models list</li><li>Upload multiple models for different voices or styles</li></ol><h3 id="step-4-configure-your-channel-voice" tabindex="-1">Step 4: Configure Your Channel Voice <a class="header-anchor" href="#step-4-configure-your-channel-voice" aria-label="Permalink to &quot;Step 4: Configure Your Channel Voice&quot;">​</a></h3><ol><li>Open your channel&#39;s <strong>Settings</strong> (gear icon on channel hover)</li><li>Under <strong>Default Voice</strong>, select <strong>RVC Voice Clone (Edge TTS + RVC)</strong> as the TTS service</li><li>Choose a <strong>Carrier Voice</strong> — this is the Edge TTS voice used as the base speech (any voice works, but pick one with similar pacing to your target)</li><li>Select your <strong>RVC Voice Model</strong> from the dropdown (shows all installed models)</li><li>Click <strong>Save</strong></li></ol><p>When you create an audio project, it will use this two-stage pipeline:</p><ol><li>Edge TTS generates the base speech with the carrier voice</li><li>RVC converts the carrier audio into your cloned voice</li></ol><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>The carrier voice affects pacing and inflection but not the final timbre — RVC replaces the voice character entirely. Edge TTS is free, so the full RVC pipeline costs nothing.</p></div><h3 id="quick-test" tabindex="-1">Quick Test <a class="header-anchor" href="#quick-test" aria-label="Permalink to &quot;Quick Test&quot;">​</a></h3><p>After configuring, go to <strong>Audio &gt; Create</strong>, select a script, and click <strong>Create Project</strong>. The service will show &quot;RVC Voice Clone&quot; and your model name. Generate a section to hear the result.</p><h2 id="preview" tabindex="-1">Preview <a class="header-anchor" href="#preview" aria-label="Permalink to &quot;Preview&quot;">​</a></h2><p>Use <strong>Preview Sections</strong> to see how your script will be split before creating a project.</p><p><img src="'+o+'" alt="Audio Sections"></p>',69)])])}const f=t(s,[["render",n]]);export{m as __pageData,f as default};
